firmware_template.source:
#include "button_debounce.h"
#include <Arduino.h>
static uint8_t _pin=0;static bool _state=false,_lastState=false,_pressed=false,_released=false;
static unsigned long _lastDebounce=0,_pressStart=0;static uint32_t _cnt=0;
void btn_setup(uint8_t p){_pin=p;pinMode(p,INPUT_PULLUP);Serial.printf("[btn] OK pin=%d\n",p);}
void btn_loop(){bool r=!digitalRead(_pin);_pressed=false;_released=false;if(r!=_lastState)_lastDebounce=millis();if(millis()-_lastDebounce>50){if(r!=_state){_state=r;if(_state){_pressed=true;_pressStart=millis();_cnt++;}else{_released=true;}}}_lastState=r;}
bool btn_pressed(){return _pressed;}
bool btn_released(){return _released;}
bool btn_held(uint16_t ms){return _state&&(millis()-_pressStart>=ms);}
uint32_t btn_press_count(){return _cnt;}
